parameters.jsonBody:
={
  "from": "{{ $env.CLINIC_FROM_EMAIL }}",
  "to": ["{{ $json.doctor_email }}"],
  "subject": "New Appointment: {{ $json.patient_name }} — {{ $json.scheduled_date }} at {{ $json.scheduled_time }}",
  "html": "<div style='font-family: Arial, sans-serif; max-width: 600px; margin: auto; padding: 30px;'><div style='background: #1e40af; color: white; padding: 20px; border-radius: 8px 8px 0 0;'><h2 style='margin:0'>New Appointment Booked</h2></div><div style='border: 1px solid #e2e8f0; border-top: none; padding: 25px; border-radius: 0 0 8px 8px;'><p>Dear {{ $json.doctor_name }},</p><p>A new appointment has been confirmed.</p><table style='width:100%; border-collapse: collapse; margin: 20px 0;'><tr style='background: #f8fafc;'><td style='padding: 10px; border: 1px solid #e2e8f0; font-weight: bold;'>Patient</td><td style='padding: 10px; border: 1px solid #e2e8f0;'>{{ $json.patient_name }}</td></tr><tr><td style='padding: 10px; border: 1px solid #e2e8f0; font-weight: bold;'>Date</td><td style='padding: 10px; border: 1px solid #e2e8f0;'>{{ $json.scheduled_date }}</td></tr><tr style='background: #f8fafc;'><td style='padding: 10px; border: 1px solid #e2e8f0; font-weight: bold;'>Time</td><td style='padding: 10px; border: 1px solid #e2e8f0;'>{{ $json.scheduled_time }}</td></tr><tr><td style='padding: 10px; border: 1px solid #e2e8f0; font-weight: bold;'>Reason</td><td style='padding: 10px; border: 1px solid #e2e8f0;'>{{ $json.reason || 'Not specified' }}</td></tr></table><p style='color: #6b7280; font-size: 13px;'>The patient will complete an AI pre-visit check-in before the appointment. You will receive another notification when their intake is complete.</p></div></div>"
}
